	private static IReadOnlyList<(string Name, int Weight)> SplitWeightedEntries(string values)
	{
		return values
			.Split('|', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
			.Select(x => (Name: x, Weight: 100))
			.ToList();
	}

	private void SeedModernEthnicityProfiles()
	{
		foreach (ModernEthnicityProfileSeed seed in ModernEthnicityProfileSeeds)
		{
			NameCulture culture = seed.NameOrder == ModernNameOrder.FamilyGiven
				? EnsureModernFamilyGivenCulture(seed.CultureName)
				: EnsureModernGivenFamilyCulture(seed.CultureName);

			SeedGivenFamilyProfile(
				$"{seed.CultureName} Male",
				Gender.Male,
				culture,
				SplitWeightedEntries(seed.MaleNames),
				SplitWeightedEntries(seed.Surnames));
			SeedGivenFamilyProfile(
				$"{seed.CultureName} Female",
				Gender.Female,
				culture,
				SplitWeightedEntries(seed.FemaleNames),
				SplitWeightedEntries(seed.Surnames));
		}
	}

	private NameCulture EnsureModernFamilyGivenCulture(string name)
	{
		return AddNameCulture(name, @"^(?<surname>[\w'-]+)\s+(?<birthname>[\w'-]+)$",
			new[]
			{
				("Family Name", 1, 1, "Your family name identifies your wider family or clan and comes first.", NameUsage.Surname),
				("Given Name", 1, 1, "Your given name follows your family name and is the personal name chosen for you.", NameUsage.BirthName)
			},
			new[]
			{
				(NameStyle.GivenOnly, "{0}", new[] { NameUsage.BirthName }),
				(NameStyle.SimpleFull, "{0} {1}", new[] { NameUsage.Surname, NameUsage.BirthName }),
				(NameStyle.FullName, "{0} {1}", new[] { NameUsage.Surname, NameUsage.BirthName }),
				(NameStyle.Affectionate, "{0}", new[] { NameUsage.BirthName }),
				(NameStyle.SurnameOnly, "{0}", new[] { NameUsage.Surname }),
				(NameStyle.FullWithNickname, "{0} {1}", new[] { NameUsage.Surname, NameUsage.BirthName })
			});
	}
